#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005;
int n,k,a[N];
deque<int> dq1,dq2;// 1mn 2mx
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>k;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=n;i++)
	{
		while(!dq1.empty()&&a[dq1.front()]>=a[i]) dq1.pop_front();
		dq1.push_front(i);
		while(!dq1.empty()&&dq1.back()<i-k+1) dq1.pop_back();
		if(i>=k) cout<<a[dq1.back()]<<" ";
	}
	cout<<"\n";
	for(int i=1;i<=n;i++)
	{
		while(!dq2.empty()&&a[dq2.front()]<=a[i]) dq2.pop_front();
		dq2.push_front(i);
		while(!dq2.empty()&&dq2.back()<i-k+1) dq2.pop_back();
		if(i>=k) cout<<a[dq2.back()]<<" ";
	}
	cout<<"\n";
	return 0;
}
